;(function(){System.register([],function(exports,module){'use strict';return{execute:function(){(Drupal2=>{const ouiBackToTop={elements:{backToTop:document.querySelector('[data-oui-back-to-top-js="data-oui-back-to-top"]')},methods:{initialize:()=>{if(!ouiBackToTop.elements.backToTop){return;}ouiBackToTop.methods.displayBackToTopButton();ouiBackToTop.event.windowScroll();ouiBackToTop.event.clickBackToTopButton();},displayBackToTopButton:()=>{if(window.scrollY>300){ouiBackToTop.elements.backToTop.classList.add("show");}else{ouiBackToTop.elements.backToTop.classList.remove("show");}}},event:{windowScroll:()=>{window.addEventListener("scroll",ouiBackToTop.methods.displayBackToTopButton);},clickBackToTopButton:()=>{ouiBackToTop.elements.backToTop.addEventListener("click",()=>{window.scrollTo({top:0,left:0,behavior:"smooth"});});}},attach:()=>{ouiBackToTop.methods.initialize();}};Drupal2.behaviors.ouiBackToTop=ouiBackToTop;})(Drupal);}};});})();
